function removeCharAt(s, i) {
	const tmp = s.split(''); // convert to an array
	tmp.splice(i - 1, 1); // remove 1 element from the array (adjusting for non-zero-indexed counts)
	return tmp.join(''); // reconstruct the string
}

export default function (input, strength = 1) {
	// To lower case
	input = input.toLowerCase();

	// Replace punctuation
	let punctuationReplacer;
	if (strength === 0) {
		punctuationReplacer = '.';
	} else if (strength === 1) {
		punctuationReplacer = ['.', '', ''][Math.floor(Math.random() * 3)];

		// Remove some elements
		input = input.replace(/[()]/g, '');
	} else if (strength === 2) {
		punctuationReplacer = '';

		// Replace some elements with spaces
		input = input.replace(/[-]/g, ' ');
	}

	input = input.replace(/[.,;]/g, punctuationReplacer);

	// Remove some random letters.
	let removeLetterPercent = 0;
	if (strength === 0) removeLetterPercent = 0.97;
	else if (strength === 1) removeLetterPercent = 0.95;
	else if (strength === 2) removeLetterPercent = 0.85;
	for (let i = input.length - 1; i >= 0; i--) {
		if (Math.random() > removeLetterPercent) input = removeCharAt(input, i);
	}

	return input;
}

