<template>
	<div id="hiddinator">
		<div class="input">
			<div class="settings">
				<h3>Mode</h3>
				<div>
					<button :class="strength === 0 ? 'active' : ''" @click="strength = 0">Simple</button>
					<button :class="strength === 1 ? 'active' : ''" @click="strength = 1">Medium</button>
					<button :class="strength === 2 ? 'active' : ''" @click="strength = 2">Extreme</button>
				</div>
			</div>
			<textarea placeholder="Text to Hiddify" id="input" rows="1" v-model="input"></textarea>
		</div>
		<div class="output">
			<textarea placeholder="Output" readonly v-model="output"></textarea>
		</div>
	</div>
</template>

<script>
	import hiddinate from '@/scripts/projects/hiddinator/hiddinator';

	export default {
		name: 'Hiddinator',
		data() {
			return {
				input: '',
				strength: 1
			};
		},
		computed: {
			output() {
				return hiddinate(this.input, parseInt(this.strength));
			}
		}
	};
</script>

